  KEY `type_company_time_user_goods` (`type`,`company`,`time`,`user`,`goods`) USING BTREE,
  KEY `company_time_user_goods` (`company`,`time`,`user`,`goods`) USING BTREE,
  KEY `time_user_goods` (`time`,`user`,`goods`) USING BTREE,
  KEY `user_goods` (`user`,`goods`) USING BTREE,
  KEY `goods` (`goods`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 ROW_FORMAT=COMPACT;


DROP TABLE IF EXISTS `is_supplier`;
CREATE TABLE `is_supplier` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(36) NOT NULL COMMENT '名称',
  `number` varchar(36) DEFAULT '' COMMENT '编号',
  `contacts` varchar(36) DEFAULT '' COMMENT '联系人',
  `tel` varchar(36) DEFAULT '' COMMENT '手机号',
  `add` varchar(128) DEFAULT '' COMMENT '地址',
  `accountname` varchar(128) DEFAULT '' COMMENT '开户名',
  `openingbank` varchar(128) DEFAULT '' COMMENT '开户行',
  `bankaccount` varchar(128) DEFAULT '' COMMENT '银行账号',
  `tax` varchar(128) DEFAULT '' COMMENT '税号',
  `other` varchar(128) DEFAULT '' COMMENT '社交账号',
  `email` varchar(128) DEFAULT '' COMMENT '邮箱',
  `data` varchar(128) DEFAULT '' COMMENT '备注信息',
  PRIMARY KEY (`id`),
  KEY `name_number_contacts_tel_data` (`name`,`number`,`contacts`,`tel`,`data`) USING BTREE,
  KEY `number_contacts_tel_data` (`number`,`contacts`,`tel`,`data`) USING BTREE,
  KEY `contacts_tel_data` (`contacts`,`tel`,`data`) USING BTREE,
  KEY `tel_data` (`tel`,`data`) USING BTREE,
  KEY `data` (`data`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='供应商';


DROP TABLE IF EXISTS `is_sys`;
CREATE TABLE `is_sys` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `info` text NOT NULL COMMENT '配置项',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='系统配置';

