DROP TABLE IF EXISTS `is_unit`;
CREATE TABLE `is_unit` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(36) NOT NULL COMMENT '名称',
  `number` varchar(36) DEFAULT '' COMMENT '编号',
  `data` varchar(128) DEFAULT '' COMMENT '备注信息',
  PRIMARY KEY (`id`),
  KEY `name_number_data` (`name`,`number`,`data`) USING BTREE,
  KEY `number_data` (`number`,`data`) USING BTREE,
  KEY `data` (`data`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='计量单位';


DROP TABLE IF EXISTS `is_user`;
CREATE TABLE `is_user` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user` varchar(36) NOT NULL COMMENT '用户账号',
  `pwd` varchar(32) NOT NULL COMMENT '用户密码',
  `name` varchar(36) NOT NULL COMMENT '用户名称',
  `tel` varchar(36) NOT NULL COMMENT '手机号码',
  `data` varchar(128) DEFAULT '' COMMENT '备注信息',
  `token` varchar(30) DEFAULT '' COMMENT '登录秘钥',
  `auth` text COMMENT '数据授权',
  `root` text COMMENT '功能设置',
  `type` int(11) NOT NULL COMMENT '用户类型',
  PRIMARY KEY (`id`),
  KEY `user_pwd_name_tel_token` (`user`,`pwd`,`name`,`tel`,`token`) USING BTREE,
  KEY `name_tel_data` (`name`,`tel`,`data`) USING BTREE,
  KEY `token` (`token`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='用户信息表';

