DROP TABLE IF EXISTS `is_warehouse`;
CREATE TABLE `is_warehouse` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(36) NOT NULL COMMENT '仓库名称',
  `number` varchar(36) DEFAULT '' COMMENT '仓库编号',
  `contacts` varchar(36) DEFAULT '' COMMENT '联系人',
  `tel` varchar(36) DEFAULT '' COMMENT '联系方式',
  `add` varchar(128) DEFAULT '' COMMENT '地址信息',
  `data` varchar(128) DEFAULT '' COMMENT '备注信息',
  PRIMARY KEY (`id`),
  KEY `name_number_contacts_tel` (`name`,`number`,`contacts`,`tel`) USING BTREE,
  KEY `number_contacts_tel` (`number`,`contacts`,`tel`) USING BTREE,
  KEY `contacts_tel` (`contacts`,`tel`) USING BTREE,
  KEY `tel` (`tel`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='仓库';


